function newDataTable(tipo) {

  if (tipo == 'MovCaixas') {
      $('#dt-basic-venda-ativa').dataTable({
          destroy: true,
          responsive: true,
          fixedHeader: true,
          colReorder: true
      });
      $('#dt-basic-venda-cancelada').dataTable({
          destroy: true,
          responsive: true,
          fixedHeader: true,
          colReorder: true
      });
  } else {
      $('#dt-basic-' + tipo).dataTable({
          destroy: true,
          responsive: true,
          fixedHeader: true,
          colReorder: true
      });
  }

  $('#dt-buttons-' + tipo).dataTable({
      responsive: true,
      lengthChange: false,
      dom:
      /*	--- Layout Structure 
          --- Options
          l	-	length changing input control
          f	-	filtering input
          t	-	The table!
          i	-	Table information summary
          p	-	pagination control
          r	-	processing display element
          B	-	buttons
          R	-	ColReorder
          S	-	Select

          --- Markup
          < and >				- div element
          <"class" and >		- div with a class
          <"#id" and >		- div with an ID
          <"#id.class" and >	- div with an ID and a class

          --- Further reading
          https://datatables.net/reference/option/dom
          --------------------------------------
          */
          "<'row mb-3'<'col-sm-12 col-md-6 d-flex align-items-center justify-content-start'f><'col-sm-12 col-md-6 d-flex align-items-center justify-content-end'lB>>" +
          "<'row'<'col-sm-12'tr>>" +
          "<'row'<'col-sm-12 col-md-5'i><'col-sm-12 col-md-7'p>>",
      order: ([1, 'desc']),
      buttons: [{
              extend: 'colvis',
              text: 'Mostrar Colunas',
              titleAttr: 'Visualizar e Esconder Colunas',
              className: 'mr-sm-3'
          },
          {
              extend: 'pdfHtml5',
              text: 'PDF',
              titleAttr: 'Gerar PDF',
              className: 'btn-outline-danger btn-sm mr-1'
          },
          {
              extend: 'excelHtml5',
              text: 'Excel',
              titleAttr: 'Gerar Excel',
              className: 'btn-outline-success btn-sm mr-1'
          },
          {
              extend: 'print',
              text: 'Imprimir',
              titleAttr: 'Imprimir Tabela',
              className: 'btn-outline-primary btn-sm'
          }
      ]
  });

}

