function retornoListaFabricanteSelect(respostaListaFabricanteSelect) {
  listaFornecedores = respostaListaFabricanteSelect.data;
  numPage = parseInt(respostaListaFabricanteSelect.page);
  if (numPage === 1) {
    $("#idfabselect").empty();
    $('#idfabselect').append(
      `<option value="">Selecione ...</option>`
    );
  }

  if (respostaListaFabricanteSelect.data.length != 0) {
    for (var i = 0; i < respostaListaFabricanteSelect.data.length; i++) {

      IDFabricante = respostaListaFabricanteSelect.data[i]['IDFABRICANTE'];
      DSFabricante = respostaListaFabricanteSelect.data[i]['DSFABRICANTE'];

      $('#idfabselect').append(
        `<option value="` + IDFabricante + `"> ` + IDFabricante + ` - ` + DSFabricante + `</option>`
      );
      $('#idfabvincselect').append(
        `<option value="` + IDFabricante + `"> ` + IDFabricante + ` - ` + DSFabricante + `</option>`
      );
    }
    //chamarProximaListaFabricanteSelect(numPage + 1);
  }

}

