async function montarSelectBuscaDinamicaFornecedores(idElement = 'idforn', idForn) {
  try {
    let preLoading = (await ajaxGet(`api/compras/fornecedor.xsjs?pageSize=500${idForn ? ('&id=' + idForn) : ''}`).catch((error) => { throw error }))?.data;
    let optionSelected;
    let data;

      idElement = !idElement ? 'idforn' : idElement;

    $('#' + idElement).append(`
      <option value="0"> Selecione ... </option>
    `);

    preLoading.map(function (item) {
      $('#' + idElement).append(`
        <option 
            value="${item.IDFORNECEDOR}"
            noRazao="${item.NORAZAOSOCIAL}"
            noFantasia="${item.NOFANTASIA}"
            cnpj="${item.NUCNPJ}"
            stAtivo="${item.STATIVO}" 
            stAtivoSap="${item?.STATIVOSAP || ''}"       
        > 
            ${item.NOFANTASIA + ' / / ' + item.NUCNPJ + ' / / ' + item.NORAZAOSOCIAL} 
        </option>
      `);
    });

    $('#' + idElement).on('select2:select', (e) => {
      optionSelected = e.params.data;
    })

    $('#' + idElement).select2({
      dropdownAutoWidth: false,
      language: {
        errorLoading: function (error) {
          return "Erro ao carregar a lista de fornecedores, Recarregue e tente novamente!";
        }
      },
      ajax: {
        dataType: 'json',
        delay: 350,
        transport: async function (params, success, failure) {
          try {
            let termoDigitado = params.data.term;
            data = preLoading;

            if (termoDigitado?.length > 1) {
              data = (
                await ajaxGet('api/compras/fornecedor.xsjs?pageSize=500&descFornOrCnpj=' + termoDigitado)
                  .catch((error) => {
                    console.log('Teste: ', error)
                    throw error;

                  })
              )?.data;

            }

              if (data?.length) {

                  let results = data.map(function (item) {
                      return {
                          id: item.IDFORNECEDOR,
                          text: `${item.NOFANTASIA + ' / / ' + item.NUCNPJ + ' / / ' + item.NORAZAOSOCIAL}`,
                          noRazao: item.NORAZAOSOCIAL,
                          noFantasia: item.NOFANTASIA,
                          cnpj: item.NUCNPJ,
                          stAtivo: item.STATIVO,
                          stAtivoSap: item?.STATIVOSAP || ''
                      };
                  });
                  success({ results });
              }
          } catch (error) {
            console.log(error);
            failure();
          }
        },
        cache: true,
        processResults: function (data) {
          let { results } = data;

          if (optionSelected?.id) {
            let indexExists = results.findIndex(item => item.id == optionSelected.id);

            if (indexExists !== -1) {
              results.splice(indexExists, 1);
            }

            results.unshift(optionSelected);

          }

          if (!results.some(item => item.id == '0')) {
            results.unshift(
              {
                id: '0',
                text: 'Selecione ...'
              }
            );
          }

          return { results };
        }
      }
    });

    if (idForn) {
      $('#' + idElement).val(idForn).trigger('change');
    } else {
      $('#' + idElement).val('0').trigger('change');
    }

  } catch (error) {
    console.log(error);
    msgError('Erro a lista de Fornecedores, Recarregue e tente novamente!');
  }
}

async function montarSelectBuscaDinamicaFabricantes(idElement = 'fabprod', idFab) {
  try {
    let preLoading = (await ajaxGet(`api/compras/fabricante.xsjs?pageSize=500${idFab ? ('&id=' + idFab) : ''}`).catch((error) => { throw error }))?.data;
    let optionSelected;
    let data;

      idElement = !idElement ? 'fabprod' : idElement;

    $('#' + idElement).append(`
        <option value="0"> Selecione ... </option>
      `);


    preLoading.map(function (item) {
      $('#' + idElement).append(`
              <option value="${item.IDFABRICANTE}"> ${item.IDFABRICANTE + ' - ' + item.DSFABRICANTE} </option>
          `);
    });

    $('#' + idElement).on('select2:select', (e) => {
      optionSelected = e.params.data;
    })

    $('#' + idElement).select2({
      dropdownAutoWidth: false,
      language: {
        errorLoading: function (error) {
          return "Erro ao carregar a lista de marcas, Recarregue e tente novamente!";
        }
      },
      ajax: {
        dataType: 'json',
        delay: 350,
        transport: async function (params, success, failure) {
          try {
            if (!data?.length) {
              data = preLoading;
            }
            let termoDigitado = params.data.term;

            if (termoDigitado?.length > 1) {
              await ajaxGet('api/compras/fabricante.xsjs?pageSize=250&page=1&descFab=' + termoDigitado)
                .then((resp) => {
                  data = resp.data
                })
                .catch((error) => {
                  console.log(error);
                  throw error;
                });
            }

            if (data?.length) {
              let results = data.map(function (item) {

                return {
                  id: item.IDFABRICANTE,
                  text: `${item.IDFABRICANTE + ' - ' + item.DSFABRICANTE}`
                };
              });

              success({ results });
            }

          } catch (error) {
            failure(error);
            throw error;
          }
        },
        cache: true,
        processResults: function (data) {
          let { results } = data;

          if (optionSelected?.id) {
            let indexExists = results.findIndex(item => item.id == optionSelected.id);

            if (indexExists !== -1) {
              results.splice(indexExists, 1);
            }

            results.unshift(optionSelected);

          }

          if (!results.some(item => item.id == '0')) {
            results.unshift(
              {
                id: '0',
                text: 'Selecione ...'
              }
            );
          }

          return { results };
        }
      }
    });

    if (idFab) {
      $('#' + idElement).val(idFab).trigger('change');
    } else {
      $('#' + idElement).val('0').trigger('change');
    }

  } catch (error) {
    console.log(error);
    msgError('Erro a lista de Marcas, Recarregue e tente novamente!');
  }
}

