function conciliarProdutoPedidoIndividualmente(idPedido, idProduto, qtdProdPedido, idDetPedido, idDetProdPedido) {
  let modalLoading = setTimeout(() => animacaoCarregamento(), delayMaximo);

  ajaxGet('api/cadastro/vincula_nfpedido.xsjs?idPedido=' + idPedido)
    .then((RespostaDadosNotaRegistrada) => {
      retornoConciliarProdutoPedidoIndividualmente(RespostaDadosNotaRegistrada, idProduto, qtdProdPedido, idDetPedido, idDetProdPedido, idPedido);
      clearTimeout(modalLoading);
      Swal.close();
    })
    .catch((e) => {
      clearTimeout(modalLoading);
      Swal.close();

      msgError();
      console.log(e);
    });
}

function retornoConciliarProdutoPedidoIndividualmente(RespostaDadosProdutosNotaRegistrada, idProduto, qtdProdPedido, idDetPedido, idDetProdPedido, idPedido) {

  qtdProdPedidoConciliar = +qtdProdPedido;
  historicoNum = qtdProdPedidoConciliar
  var dadosNFEVinculada = RespostaDadosProdutosNotaRegistrada.data.length ? RespostaDadosProdutosNotaRegistrada.data : "";

  if (dadosNFEVinculada) {
    var dadosParaTabela = [];

    for (let i = 0; i < dadosNFEVinculada.length; i++) {
      var indiceNota = i + 1;
      var ResumoEntrada = dadosNFEVinculada[i]['IDRESUMOENTRADA'];
      var dtCadastro = dadosNFEVinculada[i]['DTCADASTRO'] ? dadosNFEVinculada[i]['DTCADASTRO'] : "";
      var dtEmissao = dadosNFEVinculada[i]['DEMI'];
      var nomFornecedor = dadosNFEVinculada[i]['EMIT_XNOME'];
      var numSerieNota = dadosNFEVinculada[i]['SERIE'];
      var numNota = dadosNFEVinculada[i]['NNF'];
      var dadosNota = [ResumoEntrada, `${numSerieNota}-${numNota}`];
      var opcoes = `
                <div class="btn-group btn-group-xs">
                <button id="detalheNotaFiscal" type="button" class="btn btn-info btn-xs" title="Detalhar Produtos da Nota" value=${dadosNota}><i class="fal fa-shopping-bag pr-2"></i>Produtos</button>
                </div>
            `;

      dadosParaTabela.push([
        indiceNota,
        dtCadastro,
        dtEmissao,
        nomFornecedor,
        numSerieNota,
        numNota,
        opcoes
      ])
    }

  }
  $("#btnConciliar").addClass('d-none');
  $("#listaProdutosNFEPedido").modal('show');

  $('#tabelaProdutosNFEPedido').html(
    `<table id="dt-basic-list-produtos-nfe" class="table table-bordered table-hover table-striped w-100 ">
        <thead class="bg-primary-600">
            <tr >
                <th>#</th>
                <th><b>Data Cadastro<b></th>
                <th><b>Data Emissão<b></th>
                <th><b>Fornecedor<b></th>
                <th><b>Série<b></th>
                <th><b>NFE<b></th>
                <th><b>Opções<b></th>
            </tr>
        </thead>
        <tbody>
        </tbody>
    </table>`
  );

  let tableProdutosNFE = $('#dt-basic-list-produtos-nfe').DataTable({
    data: dadosParaTabela,
    "language": { "emptyTable": "Não Há Notas Vinculadas a Este Pedido! Adicione Uma Nota Fiscal!" },
    "columnDefs": [
      { "width": "5%", "targets": [0] },
      { "width": "10%", "targets": [1, 2, 4, 5] },
      { "width": "40%", "targets": [3] },
      { "width": "10%", "targets": [2] },
      { "width": "15%", "targets": [3] },
      { "width": "10%", "targets": [6] },
      { "className": 'text-center', "targets": [0, 1, 2, 3, 4, 5] },//, 4, 5, 6, 7, 8, 9] },

    ],
    "displayLength": 25,
  });

  $('#dt-basic-list-produtos-nfe tbody').on('click', 'button#detalheNotaFiscal', function () {
    let tr = $(this).closest('tr');
    let row = tableProdutosNFE.row(tr);
    let idNotaLinha;
    let fornecedor = $(tr[0].children[3]).text()
    let nota;

    if (tr.hasClass('child')) {
      tr = $($(`#${$(this).attr('value')}`).closest('tr'))

      row = tableProdutosNFE.row(tr);
      idNotaLinha = (this.value.split(','))[0];
      nota = (this.value.split(','))[1];
      // tr.removeClass('parent'); 
      row.child.hide();
      tr.removeClass('shown');

    } else {
      row = tableProdutosNFE.row(tr);
      idNotaLinha = (this.value.split(','))[0];
      nota = (this.value.split(','))[1];

    }

    if (row.child.isShown()) {
      // This row is already open - close it
      row.child.hide();
      tr.removeClass('shown');

    } else {
      let modalLoading = setTimeout(() => animacaoCarregamento(), delayMaximo);

      ajaxGet(`api/cadastro/cadastro_produto_nfpedido.xsjs?id=${idNotaLinha}`)
        .then((dadosDetalheNFE) => {
          ajaxGet(`api/cadastro/conciliar_nfeProd_pedidoProd.xsjs?idDetPedido=${idDetPedido}&idDetProdPedido=${idDetProdPedido}&idProduto=${idProduto}`)
            .then((dadosDetalheVinculo) => {
              row.child(formatDataTableAccordionProdutosNotaFiscal(dadosDetalheNFE, dadosDetalheVinculo, nota, fornecedor, idProduto, idDetPedido, idDetProdPedido, idPedido)).show();

              clearTimeout(modalLoading);
              Swal.close();
            })
            .catch(() => {
              clearTimeout(modalLoading);
              Swal.close();
              msgError();
            }
            )
        })
        .catch(() => {
          clearTimeout(modalLoading);
          Swal.close();
          msgError();
        })

      tr.addClass('shown');
    }

  });
}

function mascaraNumero(dados, funcao) {
  v_obj = dados;
  v_fun = funcao;

  setTimeout('execmascara()', 1)
}

function execmascara() {
  v_obj.value = v_fun(v_obj.value)
}

function formataNumero(numero) {
  numero = +numero.replace(/\D/g, "");
  var numeroFormatado = numero.toFixed(3).split('.');
  numeroFormatado = numeroFormatado[0].split(/(?=(?:...)*$)/).join('.');

  return numeroFormatado
}

function historicoDigitado(valor) {
  historicoDig = valor.replace(/\D/g, "")
  historicoNum <= 0 && historicoDig <= qtdProdPedidoConciliar ? historicoNum = +historicoDig : 0;
}

function atualizaHistorico(valor) {
  let vrDigitado = valor.replace(/\D/g, "");
  let vrInputs = $('[name=qtdProdConciliar]');
  let vrDigitados = 0;
  let tr = $(v_obj).closest('tr');
  let btnsChkQtdConciliar;

  qtdProdNota = $(tr[0].children[6]).text();
  btn = $(tr[0].children[9]);

  let htmlBtnCheck = `
    <button name="btnChkQtd" type="button" class="btn btn-success btn-xs" value=${qtdProdNota} style="width: 110px;"><i class="fal fa-check"></i></button>
  `;

  for (i = 0; i < vrInputs.length; i++) {
    var vrInputsFormatado = vrInputs[i].value;
    vrDigitados += +vrInputsFormatado.replace(/\D/g, "");
  }

  if (vrDigitados > 0 && vrDigitados <= qtdProdPedidoConciliar && +vrDigitado <= +qtdProdNota) {

    $(btn).html(htmlBtnCheck);

    $("#btnConciliar").removeClass('d-none');

    historicoNum = qtdProdPedidoConciliar;
    historicoNum = historicoNum - vrDigitados;

    if (vrDigitados == qtdProdPedidoConciliar) {

      Swal.fire({
        type: 'success',
        title: 'Todas as unidades já foram distribuídas, faça a conciliação!'
      });
    }

  } else if (vrDigitados > qtdProdPedidoConciliar) {

    $(btn).html(`
        <label style="color: blue; font-size: 11px;"> Digite a Quantidade!</label>
    `);

    $("#btnConciliar").addClass('d-none');

    Swal.fire({
      type: 'info',
      title: `Quantidade digitada maior que a restante no pedido! Quantidade Restante: ${historicoNum}`
    });

    historicoDig > 0 ? $(btn).html(htmlBtnCheck) : '';

    v_obj.value = 0;
  } else if (+vrDigitado > +qtdProdNota) {

    $(btn).html(`
        <label style="color: blue; font-size: 11px;"> Digite a Quantidade!</label>
    `);

    Swal.fire({
      type: 'info',
      title: `Quantidade digitada maior que a da Nota! Quantidade Disponivel na Nota: ${qtdProdNota}`
    });

    historicoDig > 0 ? $(btn).html(htmlBtnCheck) : '';

    v_obj.value = 0;
  }

  if (vrDigitado == 0) {
    $(btn).html(`
        <label style="color: blue; font-size: 11px;"> Digite a Quantidade!</label>
    `);
    $("#btnConciliar").addClass('d-none');

    historicoNum = qtdProdPedidoConciliar;
    historicoNum = historicoNum - vrDigitados;
  }

  btnsChkQtdConciliar = $('[name=btnChkQtd]');
  btnsChkQtdConciliar.length > 0 ? $("#btnConciliar").removeClass('d-none') : $("#btnConciliar").addClass('d-none');

}

function formatDataTableAccordionProdutosNotaFiscal(dadosDetalheNFE, dadosDetalheVinculo, notaFiscal, fornecedor, idProduto, idDetPedido, idDetProdPedido, idPedido) {
  let dadosDetalhe = dadosDetalheNFE.data.length ? dadosDetalheNFE.data : "";
  let dadosDetalheVinc = dadosDetalheVinculo.data.length ? dadosDetalheVinculo.data : "";
  let nota = notaFiscal;
  let contadorDet = 0;
  let conciliado = false;

  dadosDetalhe.sort((a, b) => a['IDDETALHEENTRADA'] - b['IDDETALHEENTRADA']);

  html = `
    <div class="row">
      <div class="col-xl-12 col-sm-12">
        <div id="panel-1" class="panel">
          <div class="panel-hdr">
              <h2>Produtos da Nota Fiscal: ${nota}</h2>
          </div>
          <div class="panel-container show">
              <div class="panel-content">
                <table id="DetalheProdutos" class="table table-bordered table-hover table-striped table-active w-100 text-center">
                  <caption class="fw-700">Fornecedor: ${fornecedor.toUpperCase()}</caption>
                  <thead class="thead-dark">
                    <tr>
                      <th><b>#<b></th>
                      <th><b>Produto<b></th>
                      <th><b>Referência<b></th>
                      <th><b>NCM<b></th>
                      <th><b>Vr Unitario<b></th>
                      <th><b>QTD Nota<b></th>
                      <th><b>QTD Disponível<b></th>
                      <th><b>QTD Conciliar<b></th>
                      <th><b>Vr Total<b></th>
                      <th><b>Conciliar<b></th>
                    </tr>
                  </thead>
                  <tbody>`;

  for (let i = 0; i < dadosDetalhe.length; i++) {
    contadorDet++;
    let dsProduto = dadosDetalhe[i]['XPROD'] ? (dadosDetalhe[i]['XPROD'].toUpperCase()) : "";
    let refProduto = dadosDetalhe[i]['CPROD'] ? dadosDetalhe[i]['CPROD'] : "";
    let ncmProduto = dadosDetalhe[i]['NCM'] ? dadosDetalhe[i]['NCM'] : "";
    let qtdDivergencia = (dadosDetalhe[i]['QTDDIVERGENCIA'] || dadosDetalhe[i]['QTDDIVERGENCIA'] == 0) ? Number(dadosDetalhe[i]['QTDDIVERGENCIA']) : '';
    let stDivergencia = dadosDetalhe[i]['STDIVERGENCIA'] ? dadosDetalhe[i]['STDIVERGENCIA'] : '';
    let qtdProdutoNFE = dadosDetalhe[i]['QCOM'] ? Number(dadosDetalhe[i]['QCOM']) : 0;
    let vrUnitario = dadosDetalhe[i]['VUNCOM'] ? maskValor(dadosDetalhe[i]['VUNCOM']) : 'Sem Valor';
    let vrTotal = dadosDetalhe[i]['VPROD'] != 0.00 ? maskValor(dadosDetalhe[i]['VPROD']) : valorUnitario;
    let idResumoNFE = dadosDetalhe[i]['IDRESUMOENTRADA'];
    let idDetalheNFe = dadosDetalhe[i]['IDDETALHEENTRADA'];
    let qtdProdutoNFEAtual = qtdProdutoNFE;

    for (let j = 0; j < dadosDetalheVinc.length; j++) {
      if (dadosDetalheVinc[j]['IDDETALHEENTRADA'] == idDetalheNFe) {
        conciliado = true;
      } else {
        conciliado = false;
      }

    }


    (qtdDivergencia > 0 || qtdDivergencia === 0) ? qtdProdutoNFEAtual = qtdDivergencia : null;

    let LinhaJaConciliada = ((qtdDivergencia == 0 && stDivergencia == 'False') || (qtdDivergencia < 0 && stDivergencia == 'True')) ? `style="opacity: 0.5" title="ESTE ITEM DA NOTA FISCAL JÀ FOI CONCILIADO TOTALMENTE!"` : conciliado ? `style="opacity: 0.5" title="ESTE ITEM DA NOTA FISCAL JÀ FOI CONCILIADO COM O PRODUTO, REFAÇA A CONCILIAÇÃO!"` : '';
    let qtdParaConciliar = ((!qtdDivergencia && !stDivergencia) || (qtdDivergencia > 0 && stDivergencia == 'True')) && !conciliado ?
      `
            <div class="input-group d-inline-block">
              <input name="qtdProdConciliar" idPedido="${idPedido}" idResumoNFE="${idResumoNFE}" idDetalheNFe="${idDetalheNFe}" idDetPedido="${idDetPedido}" idDetProdPedido="${idDetProdPedido}"  idProdCriado="${idProduto}"  qtdprodnotalinha="${qtdProdutoNFEAtual}" type="text" style="width: 60px; text-align: center" value="0" onkeyup="mascaraNumero(this, formataNumero)"  onblur="atualizaHistorico(this.value, this)" onclick="historicoDigitado(this.value)">
            </div>
          `
      :
      ` 
            <div class="input-group d-inline-block">
              <input idPedido="${idPedido}" idResumoNFE="${idResumoNFE}" idDetalheNFe="${idDetalheNFe}" idDetPedido="${idDetPedido}" idDetProdPedido="${idDetProdPedido}"  idProdCriado="${idProduto}"  qtdprodnotalinha="${qtdProdutoNFE}" type="text" style="width: 60px; text-align: center" value="0" readonly disabled>
            </div>
          `
      ;

    let btnConciliar = ((!qtdDivergencia && !stDivergencia) || (qtdDivergencia > 0 && stDivergencia == 'True')) && !conciliado ?
      `
            <label style="color: blue; font-size: 11px;"> Digite a Quantidade!</label>
          `
      : conciliado ?
        `
            <button type="button" class="btn btn-warning btn-xs" style="width: 110px;"><i class="fal fa-lock-alt"></i></button>
          `
        :
        `
            <button type="button" class="btn btn-success btn-xs" style="width: 110px;"><i class="fal fa-check"></i></button>
          `
      ;

    html += `        
                          <tr ${LinhaJaConciliada}>
                            <td>${contadorDet}</td>
                            <td>${dsProduto}</td>
                            <td>${refProduto}</td>
                            <td>${ncmProduto}</td>
                            <td>${vrUnitario}</td>
                            <td>${qtdProdutoNFE}</td>
                            <td>${qtdProdutoNFEAtual}</td>
                            <td>${qtdParaConciliar}</td>
                            <td>${vrTotal}</td>
                            <td>${btnConciliar}</td>
                          </tr>
                     `;

  }

  html += `
                </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>`

  return html;
}

function conciliarDadosProdPedProdNFE() {
  let vrInputs = $('[name=qtdProdConciliar]');
  let dadosProdPedConciliar = [];
  let detProdutoRecepcao = [];
  let idPedido;
  let idProdCriado;
  let IDEMPRESA;
  let IDRESUMOENTRADA;
  let IDDETALHEENTRADA;
  let IDDETALHEPEDIDO;
  let IDDETALHEPRODUTOPEDIDO;
  let qtdProdNotalinha;
  let qtdDigitadaNaLinha;
  let QTDDIVERGENCIA;
  let QTDDETPRODPEDIDO;
  let QTDDETNOTA;
  let QTDVINCULO;
  let QTDFALTADETPRODPEDIDO;
  let QTDFALTADETDETNOTA;
  let STDIVERGENCIA;
  let DSOBSERVACAODIVERGENCIA;
  let qtdProd = 0;

  for (let i = 0; i < vrInputs.length; i++) {
    let vrInputsFormatado = vrInputs[i];

    if (vrInputsFormatado.value > 0) {
      idPedido = $(vrInputsFormatado).attr('idPedido');
      idProdCriado = $(vrInputsFormatado).attr('idProdCriado');
      IDRESUMOENTRADA = Number($(vrInputsFormatado).attr('idResumoNFE'));
      IDDETALHEENTRADA = Number($(vrInputsFormatado).attr('idDetalheNFe'));
      IDDETALHEPEDIDO = Number($(vrInputsFormatado).attr('idDetPedido'));
      IDDETALHEPRODUTOPEDIDO = Number($(vrInputsFormatado).attr('idDetProdPedido'));
      qtdProdNotalinha = Number($(vrInputsFormatado).attr('qtdprodnotalinha'));
      qtdDigitadaNaLinha = Number(vrInputsFormatado.value);
      QTDDIVERGENCIA = qtdProdNotalinha - qtdDigitadaNaLinha;
      QTDDETPRODPEDIDO = i == 0 ? qtdProdPedidoConciliar : Number(QTDDETPRODPEDIDO) - Number(QTDVINCULO);
      QTDDETNOTA = qtdProdNotalinha;
      QTDVINCULO = qtdDigitadaNaLinha > qtdProdNotalinha ? qtdProdNotalinha : qtdDigitadaNaLinha;
      QTDFALTADETPRODPEDIDO = QTDDETPRODPEDIDO - QTDVINCULO;
      QTDFALTADETDETNOTA = QTDDETNOTA - QTDVINCULO;
      STDIVERGENCIA;
      DSOBSERVACAODIVERGENCIA;

      qtdProd += qtdDigitadaNaLinha > qtdProdNotalinha ? qtdProdNotalinha : qtdDigitadaNaLinha;

      if (QTDDIVERGENCIA != 0) {
        STDIVERGENCIA = 'True';
        DSOBSERVACAODIVERGENCIA = QTDDIVERGENCIA > 0 ? 'Quantidade Maior na Nota' : 'Quantidade Menor na Nota';

      } else if (QTDDIVERGENCIA == 0) {
        STDIVERGENCIA = 'False';
        DSOBSERVACAODIVERGENCIA = 'Sem Divergencia';
      }

      dadosProdPedConciliar.push({
        IDRESUMOENTRADA,
        IDDETALHEENTRADA,
        IDDETALHEPEDIDO,
        IDDETALHEPRODUTOPEDIDO,
        IDPRODUTO: idProdCriado,
        QTDDETPRODPEDIDO,
        QTDDETNOTA,
        QTDVINCULO,
        QTDFALTADETPRODPEDIDO,
        QTDFALTADETDETNOTA,
        STDIVERGENCIA,
        DSOBSERVACAODIVERGENCIA,
        QTDDIVERGENCIA
      });

    }
  }

  detProdutoRecepcao.push({
    IDEMPRESA,
    IDPRODUTO: idProdCriado,
    QTD: qtdProd
  });

  dadosProdPedConciliar.push(detProdutoRecepcao);

  if (dadosProdPedConciliar.length > 0) {

    ajaxPut(`api/cadastro/conciliar_nfeProd_pedidoProd.xsjs`, dadosProdPedConciliar)
      .then((resposta) => {
        $('#listaProdutosNFEPedido').modal('hide');
        ReceberPedidoNFe(idPedido);

        Swal.fire({
          type: 'success',
          title: resposta.msg,
          timer: 2500
        })


      })
      .catch(funcError)
  } else {
    Swal.fire({
      type: 'error',
      title: 'Nenhum Valor Digitado, Digite os Valores e Tente Novamente! '
    })

    $("#btnConciliar").addClass('d-none')

    return false;
  }



}

