async function insereDadosCatalogoForn(nfeEntradaXml) {
  try {
    animationLoadingStart('Validando dados...', false, 1);

    let linhasProdutos = $('#tableProdsXml tbody tr');
    let idForn = $('#idFornecedorXML').val();
    let dados = [];
    let IDFUNCIONARIO = Number(await getCurrentUser()?.user?.id || 0);
    let IDFORNECEDOR = Number(nfeEntradaXml[0]?.IDFORNECEDOR || idForn || 0);
    let validaProds;
    let linhas = '';

    if (!IDFUNCIONARIO) {
      return msgWarning('Não foi possível identificar o usuário logado, faça o logoff e tente novamente!');
    }

    if (!IDFORNECEDOR) {
      return msgWarning('Não foi possível identificar o fornecedor, Tente novamente!');
    }

    await linhasProdutos.each(async function (index) {
      let IDPRODUTO = $(this).find('td:nth-child(2) input').attr('idproduto') || '';
      let DSPRODUTO = $(this).find('td:nth-child(3) input').attr('dsproduto') || '';
      let IDPRODUTOFORNECEDOR = $(this).find('td:nth-last-child(2)').text();
      let DSPRODUTOFORNECEDOR = $(this).find('td:nth-last-child(1+)').text();

      if (!IDPRODUTO || !$(this).find('td:nth-child(2) input').val() || !DSPRODUTO || !$(this).find('td:nth-child(3) input').val()) {
        validaProds = false;
        linhas += `${(index + 1) + (index == linhasProdutos.length - 1 ? '' : ',')}`;
      } else {

        dados.push({
          IDPRODUTO,
          DSPRODUTO,
          IDFORNECEDOR,
          IDPRODUTOFORNECEDOR,
          DSPRODUTOFORNECEDOR,
          IDFUNCIONARIO
        });

        validaProds = validaProds == false ? false : true;
      }

    });

    if (!validaProds) {
      linhas = linhas.split(',').filter(linha => linha).join(', ');

      return msgWarning(`Ainda Há Produtos Para Catalogar, linha${linhas?.length > 1 ? 's' : ''}(${linhas.replace(/,([^,]*)$/, ' e $1')}), Preencha os Campos em Branco e Tente Novamente!`);
    }

    if (!dados.length) {
      return msgError('Não foi possivel gerar os dados para cadastrar, Recarregue e tente novamente!');
    }

    animationLoadingStart('Registrando Dados...', false, 1);

    await ajaxPost('api/cadastro/cadastro_catalogo_produtos_fornecedor.xsjs', dados)
      .then(resp => {
        animationLoadingStop();

        if (resp.statusPost == 'Success') {
          msgSuccess(resp.msg)
            .then(() => {

              $('#modalGenerico').modal('hide');
              processaDadosValidadosDoXMLDaNFE(nfeEntradaXml);

            })
        } else {
          msgWarning(resp.msg);
        }

      })
      .catch((error) => { throw error; })
      ;

  } catch (error) {
    animationLoadingStop();
    console.log(error);
    msgError('Erro ao ler o arquivo, Recarregue e tente novamente!')
  }
}

async function processaDadosValidadosDoXMLDaNFE(nfeEntradaXml) {
  try {
    let dadosXml = nfeEntradaXml;

    animationLoadingStart();

    for (let i = 0; i < dadosXml[0].detProdNFE.length; i++) {
      let IDFORNECEDOR = dadosXml[0].IDFORNECEDOR;
      let CPROD = dadosXml[0].detProdNFE[i].CPROD;

      let dadosProdCatalogo = await ajaxGet(`api/cadastro/cadastro_catalogo_produtos_fornecedor.xsjs?idfornecedor=${IDFORNECEDOR}&idprodforn=${CPROD}`).catch((error)=>{ throw error; });

      dadosXml[0].detProdNFE[i].IDPRODUTO = dadosProdCatalogo.data[0]['IDPRODUTO'];
      dadosXml[0].detProdNFE[i].NUREFERENCIA = dadosProdCatalogo.data[0]['NUREFERENCIA'];
      dadosXml[0].detProdNFE[i].XPROD = dadosProdCatalogo.data[0]['DSNOME'];
      dadosXml[0].detProdNFE[i].CEAN = dadosProdCatalogo.data[0]['NUCODBARRAS'];
    }

    animationLoadingStop();
    telaEscolhaArquivoXMLDaNFEDeEntrada(dadosXml);

  } catch (error) {
    animationLoadingStop();
    console.log(error);
    msgError('Erro ao ler o arquivo, Recarregue e tente novamente!')
  }
}

function verificaDadosPreenchidosNfeComXml(dadosNfeXml) {
    let camposCabecalhoNFEDeEntrada = $('#formNFEDeEntrada :input');
    let stDadoValidados = true;

    for (let i = 0; i < camposCabecalhoNFEDeEntrada.length; i++) {
        let dados = camposCabecalhoNFEDeEntrada[i];

        if ($(dados).attr('id') !== 'idResPedNFEManual' && $(dados).attr('id') !== 'fabprod') {
          let vrDados = $(dados).hasClass('select2') && $(dados).attr('id') !== 'idTpFrete' && $(dados).attr('id') !== 'idStatusSaldo' ? Number($(dados).val()) : $(dados).val();

            if (!vrDados) {
                msgWarning(`Campo ${$(dados).closest("div").prev("label").text()} Não Preenchido, Preencha e Tente Novamente!`)
                    .then(() => {
                        setTimeout(() => {
                            $(dados).focus();
                            $(dados).hasClass('select2') && $(dados).select2('open');
                        }, 500)
                    });

                stDadoValidados = false;

                break;
            }
        }
    }

    dadosNfeXml[0].IDRESUMOPEDIDO = Number($('#idResPedNFEManual').val() || 0) || null;
    dadosNfeXml[0].IDUSOPRINCIPAL = Number($('#idUsoPrincipal').val());
    dadosNfeXml[0].IDCONDPAGAMENTO = Number($('#idcondicaopagamento').val());
    dadosNfeXml[0].STSALDO = $('#idStatusSaldo').val();
    dadosNfeXml[0].IDMARCA = Number($('#fabprod').val());
    dadosNfeXml[0].OBSERVACOES = $('#obsNotaEntrada').val();
    dadosNfeXml[0].IDCOMPRADOR = Number($('#IdCompradorPedido').val());

    if (stDadoValidados) {
        cadastrarNFEDeEntrada(dadosNfeXml);
    }
}

async function insereNotaXml(dadosNfeXml) {
  try {
    animationLoadingStart('Cadastrando nota fiscal...')

    await ajaxPost("api/cadastro/cadastrar-nota-fiscal-entrada.xsjs"/*"api/cadastro/cadastro_nfAvulsa.xsjs"*/, dadosNfeXml)
      .then(resp => {
        animationLoadingStop()

        if (resp.statusPost == 'Success') {
          $('#modalGenerico').modal('hide');

          msgSuccess(resp.msg);
        } else {
          msgWarning(resp.msg);
        }

      })
      .catch((error) => { throw error; })
  } catch (error) {
    animationLoadingStop();
    console.log(error);
    msgError('Erro ao Cadastrar Nota, Recarregue e tente novamente!');
  }
}

function funcSucessCadNFPedido(resposta, dadosDetPedidoReceber) {
  var mensagem = resposta.msg;
  if (resposta.statusPost == 'Success') {
    Swal.fire({
      type: 'success',
      title: mensagem,
      showConfirmButton: false,
      timer: 4000
    }).then(() => carregarPedidoParaConciliar(dadosDetPedidoReceber))

  } else {
    Swal.fire({
      type: 'error',
      title: 'Erro Ao Cadastrar a Nota Fiscal, Tente Novamente!',
      showConfirmButton: false,
      timer: 4000
    })
  }
}

async function modalSelecaoDeProdutosDoPedidoParaCopiarParaNFEDeEntradaManual(idPedido) {
    try {
        let detalheProdutosPedidos = (await ajaxGet(`api/cadastro/lista_produtos_criados_dos_pedidos.xsjs?idpedido=${idPedido}`).catch((error) => { throw error }))?.data;
        let produtosParaConciliar = [];

        animationLoadingStart();

        await $.get('cadastro_action_CopiarPedidoParaNota.html', async (resp) => {
            $('#resultadoModalGenerico').html(resp);
            $('#tituloGenerico').text('Cadastro/Conciliação Manual de NF-e de Entrada');
        }).fail((error) => { throw error });

        if (detalheProdutosPedidos) {
            detalheProdutosPedidos.sort((a, b) => a['IDDETALHEPRODUTOPEDIDO'] - b['IDDETALHEPRODUTOPEDIDO']);

            for (let i = 0; i < detalheProdutosPedidos.length; i++) {
                let detalheProdutosPedido = detalheProdutosPedidos[i];
                let contadorProdNota = 1;
                let idProduto = detalheProdutosPedido.IDPRODUTOCRIADO;
                let idPedido = detalheProdutosPedido.IDPEDIDO;
                var idDetPedido = detalheProdutosPedido.IDDETPEDIDO;
                let codBarras = detalheProdutosPedido.CODBARRAS;
                let refProd = detalheProdutosPedido.NUREF;
                let ncmProd = +detalheProdutosPedido.NUNCM;
                let descProd = detalheProdutosPedido.DSPRODUTOCRIADO;
                let vrUnidadeProd = detalheProdutosPedido?.VRUNITLIQDETALHEPEDIDO ? parseFloat(detalheProdutosPedido.VRUNITLIQDETALHEPEDIDO) : 0;
                let qtdUnidadeProd = detalheProdutosPedido?.QTDPRODUTOCRIADO && Number(detalheProdutosPedido.QTDPRODUTOCRIADO);
                let qtdUnidadeProdNota = detalheProdutosPedido?.QTDVINCULADO ? Number(detalheProdutosPedido.QTDVINCULADO) : 0;
                let idDetProdPedido = detalheProdutosPedido.IDDETALHEPRODUTOPEDIDO;
                let siglaUMProd = detalheProdutosPedido.DSSIGLA;
                let idUMProd = detalheProdutosPedido.IDUNIDADEMEDIDA;
                let vrTotalProd = detalheProdutosPedido?.VRTOTALCUSTOPRODCRIADO ? parseFloat(detalheProdutosPedido.VRTOTALCUSTOPRODCRIADO) : 0;

                qtdUnidadeProd = qtdUnidadeProd - qtdUnidadeProdNota;

                let selecao = qtdUnidadeProd > 0 ? `
                    <div class="custom-control custom-checkbox text-center"> 
                        <input type="checkbox" id="${codBarras}" idPedido="${idPedido}"  idDetPedido="${idDetPedido}" idProd="${idProduto}" idDetProdPedido="${idDetProdPedido}" numRef="${refProd}" descProd="${descProd}" qtdProd="${qtdUnidadeProd}" vrUnitProd="${vrUnidadeProd}" ncmProd="${ncmProd}" idUMProd="${idUMProd}" siglaUMProd="${siglaUMProd}" vrTotalProd="${vrTotalProd}" class="custom-control-input" name="prodSelecionadoParaNota" onclick="selecionaLinhaProdPedNotaManual(this.id, 'PRODUTO SELECIONADO PARA INSERIR NA NOTA!')" checked>
                        <label class="custom-control-label" for="${codBarras}"></label>
                    </div>
                    ` : `
                    <div class="custom-control custom-checkbox text-center"> 
                        <input type="checkbox" id="${codBarras}" class="custom-control-input" name="prodSelecionadoParaNota" onclick="selecionaLinhaProdPedNotaManual(this.id, 'PRODUTO INDISPONIVEL PARA INSERIR NA NOTA!')" disabled>
                        <label class="custom-control-label" for="${codBarras}"></label>
                    </div>
                ` ;

                contadorProdNota += i;

                produtosParaConciliar.push([
                    contadorProdNota,
                    selecao,
                    codBarras,
                    refProd,
                    descProd,
                    maskValor(vrUnidadeProd.toFixed(2)),
                    qtdUnidadeProd,
                    maskValor(vrTotalProd.toFixed(2))
                ]);
            }

            $('#resultadoProdParaNFE').html(`
                <table id="tableProdParaNFEManual" class="table table-bordered table-hover table-striped w-100 ">
                    <thead class="bg-primary-600">
                        <tr >
                            <th style="width: 5px; text-align: center; font-size: 12px;">#</th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Seleção<b></th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Cód.Barras<b></th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Referência<b></th>
                            <th style="width: 15px; text-align: center; font-size: 12px;"><b>Produto<b></th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Vr. Unitário<b></th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Qtd Pedido<b></th>
                            <th style="width: 10px; text-align: center; font-size: 12px;"><b>Vr.Total<b></th>
                        </tr>
                    </thead>
                    <tbody id="resultadoProdNFe">
                    </tbody>
                </table>
            `);

            $('#tableProdParaNFEManual').DataTable({
                data: produtosParaConciliar,
                "columnDefs": [
                    { "width": "10%", "targets": [3, 5, 6, 7] },
                    { "width": "35%", "targets": [4] },
                    { "width": "10%", "targets": [1, 2] },
                    { "width": "5%", "targets": [0] },
                    //{ "className": 'text-right', "targets": [4, 5, 6, 7, 8] },
                    { "className": 'text-center font-weight-bold', "targets": [0, 1, 2, 3, 4, 5, 6, 7] },

                ],
                "displayLength": 10,
            });

            let qtdPages = $('#tableProdParaNFEManual').DataTable().page.info().pages;

            for (let i = 0; i < qtdPages; i++) {
                i > 0 && $('#tableProdParaNFEManual').DataTable().page(i).draw(false);

                let prodSelecionado = $(`[name="prodSelecionadoParaNota"]`);
                for (let i = 0; i < prodSelecionado.length; i++) {
                    let linhaSelecionada = $(`#${prodSelecionado[i].id}`).closest('tr');

                    if (prodSelecionado[i].checked && !prodSelecionado[i].disabled) {
                        linhaSelecionada.addClass('selected').css("opacity", 0.8);
                        linhaSelecionada.attr('title', 'PRODUTO SELECIONADO PARA INSERIR NA NOTA!');
                    } else {
                        prodSelecionado[i].disabled ? linhaSelecionada.addClass('selected text-primary').css("opacity", 0.8) : linhaSelecionada.removeClass('selected').removeAttr('style');
                        linhaSelecionada.attr('title', 'PRODUTO JÁ CONCILIADO TOTALMENTE!');
                    }
                }

            }

            $('#tableProdParaNFEManual').DataTable().page(0).draw(false);

            $('#footerModalGenerico').html(`
                <button class="btn btn-success" type="button" onclick="modalCadastroNFEDeEntradaAPartirDoPedido(${idPedido})">
                    <span class="fal fa-paste mr-1"></span>Copiar Para Nota
                </button>
            `);

        }

        animationLoadingStop();

        $('#modalGenerico').modal('show');

    } catch (error) {
        animationLoadingStop();
        msgError();
        console.log(error);
    }
}

function selecionaLinhaProdPedNotaManual(id, msg = '') {
  let linhaSelecionada = $(`#${id}`).parent('div').parent('td').parent();

  if (!linhaSelecionada.hasClass('selected')) {
    linhaSelecionada.addClass('selected').css("opacity", 0.8);
    linhaSelecionada.attr('title', `${msg || 'PRODUTO SELECIONADO PARA INSERIR NA NOTA!'}`);

  } else {
    linhaSelecionada.removeClass('selected').removeAttr('style');
    linhaSelecionada.attr('title', 'PRODUTO DISPONIVEL PARA INSERIR NA NOTA!');

  }

}

async function modalCadastroNFEDeEntradaAPartirDoPedido(idPedido = '') {
  try {
      let prodsSelecionados = [];
      let qtdPages = $('#tableProdParaNFEManual').DataTable().page.info().pages;

      $('#tableProdParaNFEManual').DataTable().page(0).draw(false);

      for (let i = 0; i < qtdPages; i++) {
          i > 0 && $('#tableProdParaNFEManual').DataTable().page(i).draw(false);

          $('[name="prodSelecionadoParaNota"]:checked').length && prodsSelecionados.push(...$('[name="prodSelecionadoParaNota"]:checked'));

      }

    if (prodsSelecionados.length && idPedido) {

        let produtosSelecionados = [];

        animationLoadingStart();
        await modalCadastroNFEDeEntrada(false);

        for (let i = 0; i < prodsSelecionados.length; i++) {
          let idPedido = $(prodsSelecionados[i]).attr('idPedido');
          let idDetPedido = $(prodsSelecionados[i]).attr('idDetPedido');
          let idProd = $(prodsSelecionados[i]).attr('idProd');
          let idDetProdPedido = $(prodsSelecionados[i]).attr('idDetProdPedido');
          let descProd = $(prodsSelecionados[i]).attr('descProd');
          let numRef = $(prodsSelecionados[i]).attr('numRef');
          let codBarras = prodsSelecionados[i].id;
          let qtdProd = $(prodsSelecionados[i]).attr('qtdProd');
          let vrUnitProd = $(prodsSelecionados[i]).attr('vrUnitProd');
          let idUMProd = $(prodsSelecionados[i]).attr('idUMProd');
          let siglaUMProd = $(prodsSelecionados[i]).attr('siglaUMProd');
          let vrTotalProd = $(prodsSelecionados[i]).attr('vrTotalProd');
          let ncmProd = $(prodsSelecionados[i]).attr('ncmprod');

          produtosSelecionados.push({
            idPedido,
            idProd,
            idDetProdPedido,
            idDetPedido,
            descProd,
            numRef,
            codBarras,
            qtdProd,
            vrUnitProd,
            idUMProd,
            siglaUMProd,
            vrTotalProd,
            ncmProd
          });
        }

        let { data } = await ajaxGet('api/compras/lista_pedidos.xsjs?idpedido=' + idPedido).catch((error) => { throw error });

        await retornoModalCadastroNFEDeEntradaAPartirDoPedido(data, produtosSelecionados);

        animationLoadingStop();
      
    } else {
      animationLoadingStop();
      msgWarning('Selecione um produto e tente novamente!');
    }

  } catch (error) {
    console.log(error);

    animationLoadingStop();
    msgError();
  }
}

