function retornoListaCompradorSelect(respostaListaComprador) {

  $("#IdCompradorPedido").empty();
  $('#IdCompradorPedido').append(
    `<option value="">Selecione ...</option>`
  );

  for (var i = 0; i < respostaListaComprador.data.length; i++) {

    let IDCompradorPed = respostaListaComprador.data[i]['IDFUNCIONARIO'];
    let DSCompradorPed = respostaListaComprador.data[i]['NOFUNCIONARIO'];

    $('#IdCompradorPedido').append(
      `<option value="` + IDCompradorPed + `"> ` + DSCompradorPed + `</option>`
    );
  }

  $('#IdCompradorPedido').select2();
}

function retornoListaFiliaisDestino(detalhesFiliaisDestino) {
  let depositoDestinoNF = detalhesFiliaisDestino.data || "";

  if (depositoDestinoNF) {
    $('#depositoDestinoNF').html(`<option value="0" selected disabled>Selecione a Filial de Destino</option>`);

    depositoDestinoNF.sort((a, b) => a['IDEMPRESA'] - b['IDEMPRESA']);

    depositoDestinoNF.map((filial) => {
      $('#depositoDestinoNF').append(`<option value="${filial['IDEMPRESA']}" cnpj="${filial['NUCNPJ']}" idGrupoEmpresarial="${filial['IDGRUPOEMPRESARIAL']}">${filial['NOFANTASIA'] + ' - ' + filial['NORAZAOSOCIAL']}</option>`)
    })

    $('#depositoDestinoNF').select2();
  }
}

function retornoListaUsosPrincipais(detalhesUsosPrincipais) {
  let usosPrincipais = detalhesUsosPrincipais.data || "";

  if (usosPrincipais) {
    $('#idUsoPrincipal').html(`<option value="" selected disabled>Selecione o Uso Principal</option>`);

    usosPrincipais.map((usoPrincipal) => {
      $('#idUsoPrincipal').append(`<option value="${usoPrincipal['ID']}">${usoPrincipal['Usage']}</option>`)
    })

    $('#idUsoPrincipal').select2();
  }
}

function trocaCnpjDepositoDestinoNF(idFilialDestino) {
  let cnpjFilialDestino = $('#depositoDestinoNF option:selected').attr('cnpj');

  $('.idDepDestinoLinha').text(idFilialDestino)
  $('#cnpjDepositoDestinoNF').val(maskCNPJ(cnpjFilialDestino));
}

function preencheDadosComCHNFE(chaveNFE) {
    chaveNFE = chaveNFE.replace(/\D/g, "");
    
    $('#chaveNF').val(chaveNFE);

  if (chaveNFE.length == 44) {
    let dadosForn = $("#idforn").select2("data")[0];
    let cnpjForn = dadosForn?.cnpj || $(dadosForn.element).attr('cnpj')
    let cnpjNota = chaveNFE.substring(6, 20);

    if (cnpjNota !== cnpjForn) {
      return msgWarning('Está nota não Pertence ao Fornecedor Selecionado, favor verificar a nota fiscal!');
    }

    $('#modeloNF').val(chaveNFE.substring(20, 22) || "").trigger('change');
    $('#serieNF').val(parseInt(chaveNFE.substring(22, 25)) || "");
    $('#numNF').val(Number(chaveNFE.substring(25, 34)) || "");

  } else if (chaveNFE.length > 1 && chaveNFE.length < 44 || chaveNFE.length > 44) {
    msgWarning(`Chave incompleta ou maior que 44 caracteres, favor verifique a chave da nota fiscal! Nº DE CARACTERES DIGITADOS: ${chaveNFE.length}`);
  }
}

