async function modificaLinhaNFEDeEntradaApartirDoIdProduto(element) {
    try{
    let idProdutoAnterior = $(element).attr('idProduto');

    if (element.value) {
        let idFilialDest = $('#depositoDestinoNF').val();
        let idProduto = element.value ? ((element.value).trim().split(' ')).shift() : '';
        let linha = $(element).closest('tr');
        let indice = linha.index();

        if (idFilialDest) {
            animationLoadingStart();

            await ajaxGet(`api/produtos/busca-produto.xsjs?idEmpresa=${idFilialDest}&id=${idProduto}`)
                .then(resp => {
                    if (resp?.data?.length) {
                        retornoModificaLinhaNFEDeEntradaApartirDoIdProduto(resp, indice);
                    } else {
                        $(element).val(idProdutoAnterior);

                        msgError('Produto não encontrado!');
                    }
                })
                .catch((error) => { throw error })

        } else {
            msgError('Seleciona e a Filial primeiro!');
        }

        animationLoadingStop()
    } else {
        $(element).val(idProdutoAnterior);
    }

    } catch (error) {
        animationLoadingStop();
        console.log(error);
        msgError('Erro ao Carregar os dados do Produto, verifique os dados e tente novamente!')
    }
}

