function cadastrarNFEDeEntrada(dadosNFE) {
    let chaveNFE = $('#chaveNF').val()?.replace(/\D/g, "");

    $('#chaveNF').val(chaveNFE);

    if (chaveNFE.length == 44) {
        let dadosForn = $("#idforn").select2("data")[0];
        let cnpjForn = dadosForn?.cnpj || $(dadosForn.element).attr('cnpj')
        let cnpjNota = chaveNFE.substring(6, 20);

        if (cnpjNota !== cnpjForn) {
            return msgWarning('Está nota não Pertence ao Fornecedor Selecionado, favor verificar a nota fiscal!');
        }

        $('#modeloNF').val(chaveNFE.substring(20, 22) || "").trigger('change');
        $('#serieNF').val(parseInt(chaveNFE.substring(22, 25)) || "");
        $('#numNF').val(Number(chaveNFE.substring(25, 34)) || "");

    } else if (chaveNFE.length > 1 && chaveNFE.length < 44 || chaveNFE.length > 44) {
        return msgWarning(`Chave incompleta ou maior que 44 caracteres, favor verifique a chave da nota fiscal! Nº DE CARACTERES DIGITADOS: ${chaveNFE.length}`);
    }

    animationLoadingStart('Cadastrando nota fiscal...');
//return console.log(dadosNFE)
    ajaxPost("api/cadastro/cadastrar-nota-fiscal-entrada.xsjs", dadosNFE)
        .then(async (resp) => {
            animationLoadingStop();

            if (resp.statusPost == 'success') {
                $('#modalGenerico').modal('hide');

                msgSuccess(resp.msg).then(async (resp) => {
                    await pesquisaNfeCadastrada(resp?.NotaCadastrada?.IDRESUMOENTRADA);
                });
            } else {
                msgWarning(resp.msg);
            }

        })
        .catch((error) => {
            animationLoadingStop();
            msgError('Erro ao Registra a Nota, Tente novamente!');
            console.log(error)
        })
    ;

}

function cancelarDadosDigitadosNFEntradaManual() {
    Swal.fire({
        type: 'question',
        title: 'Tem certeza que deseja Cancelar?',
        text: 'Todos os dados digitados serão perdidos permanentemente!',
        confirmButtonText: 'Sim, Cancelar!',
        confirmButtonColor: '#d33',
        showCancelButton: true,
        cancelButtonText: 'Não!',
        cancelButtonColor: '#1dc9b7',
        allowOutsideClick: false,
        backdrop: false
    }).then(resp => {
        if (resp.value) {
            msgSuccess('Cadastro/Digitação cancelado com Sucesso!').then(ListaNFE);
        }
    })

}

function migrarNfeSAPManual(idResumoEntrada) {
    msgQuestion('Deseja migrar a nota para o SAP?')
    .then(async (resp) => {
        if(resp?.value){
            let dadosNFE = [
                { 
                    IDRESUMOENTRADA: idResumoEntrada 
                }
            ];

            animationLoadingStart('Migrando Nota Fiscal para o SAP...');

            ajaxPut("api/cadastro/cadastro_nfAvulsa.xsjs", dadosNFE)
                .then(async (resp) => {
                    animationLoadingStop();

                    if (resp.statusPost == 'success') {
                        $('#modalGenerico').modal('hide');

                        msgSuccess(resp.msg).then(() => pesquisaNfeCadastrada(idResumoEntrada));
                    } else {
                        msgWarning(resp.msg).then(() => pesquisaNfeCadastrada(idResumoEntrada));
                    }

                })
                .catch((e) => {
                    animationLoadingStop();
                    msgError('Erro ao Registra a Nota, Tente novamente!');
                    console.log(e)
                })
        }
    })
}

async function visualizarNfeEntrada(id = '') {
    try {
        animationLoadingStart('Carragando Nota Fiscal...');

        await modalCadastroNFEDeEntrada();

        $('#btnCadastrarNFEEntrada').addClass('d-none');

        await ajaxGet('api/cadastro/cadastro_nfpedido.xsjs?id=' + id)
            .then((resp) => {
                retornoModalVisualizarNfeEntrada(resp.data[0])
            })
            .catch((error) => {
                throw error;
            });

    } catch (error) {
        animationLoadingStop();
        msgError();
        console.log(error)
        $('#modalGenerico').modal('hide');
    }

}

async function retornoModalVisualizarNfeEntrada(detalheNotaEntrada) {
    try {
        let detalheProdutosNfe = detalheNotaEntrada.detalheProdutosNotaEntrada || '';
        let idPedidoNota = detalheNotaEntrada.IDRESUMOPEDIDO || '';
        let idMarcaNota = detalheNotaEntrada.IDMARCA || '';
        let idCompradorNota = detalheNotaEntrada.IDCOMPRADOR || '';
        let idCondPagNota = detalheNotaEntrada.IDCONDPAGAMENTO || '';
        let idUsoPrincioal = detalheNotaEntrada.IDUSOPRINCIPAL || '';
        let modFreteNota = detalheNotaEntrada.MODFRETE || '';
        let stSaldo = detalheNotaEntrada.STSALDO || '';
        let idFornNota = detalheNotaEntrada.IDFORNECEDOR || '';
        let dtCadastro = detalheNotaEntrada.DTCADASTRO || '';
        let dtEmissao = detalheNotaEntrada.DEMI || '';
        let depDestinoNota = detalheNotaEntrada.IDEMPRESA || '';
        let numNF = detalheNotaEntrada.NNF || '';
        let serieNF = detalheNotaEntrada.SERIE || 0;
        let modeloNF = detalheNotaEntrada.XMOD || '';
        let chaveNF = detalheNotaEntrada.CHNFE || '';
        let obsNota = detalheNotaEntrada.OBSERVACOES || '';
        let totalNotaEntrada = detalheNotaEntrada.VNF || 0;

        await montarSelectBuscaDinamicaFornecedores('', idFornNota).catch((error) => { throw error });

        await montarSelectBuscaDinamicaFabricantes('', idMarcaNota).catch((error) => { throw error });

        let inputsSelects = [
            { id: '#IDResPedidoAtual', value: idPedidoNota },
            { id: '#idforn', value: idFornNota },
            { id: '#fabprod', value: idMarcaNota },
            { id: '#IdCompradorPedido', value: idCompradorNota },
            { id: '#idcondicaopagamento', value: idCondPagNota },
            { id: '#idUsoPrincipal', value: idUsoPrincioal },
            { id: '#idTpFrete', value: modFreteNota },
            { id: '#idStatusNota', value: 'Fechado' },
            { id: '#idStatusSaldo', value: stSaldo },
            { id: '#dtCadastro', value: dtCadastro },
            { id: '#dtNotaEntrada', value: dtEmissao },
            { id: '#depositoDestinoNF', value: depDestinoNota },
            { id: '#numNF', value: numNF },
            { id: '#serieNF', value: serieNF },
            { id: '#modeloNF', value: modeloNF },
            { id: '#chaveNF', value: chaveNF }
        ];

        for (let inputsSelect of inputsSelects) {

            $(inputsSelect.id).val(inputsSelect.value).trigger('change');
            $(inputsSelect.id).attr('disabled', true);

        }

        let produtosNota = [];

        if (detalheProdutosNfe) {
            produtosNota = detalheProdutosNfe.map((detalheProdutos, i) => {
                let {
                    nItem,
                    IDPRODUTO,
                    DSPRODUTO,
                    NUCODBARRAS,
                    QTD,
                    EMPDESTINO,
                    VRUNITARIO,
                    VRTOTALPROD,
                } = detalheProdutos;

                return [
                    nItem,
                    IDPRODUTO,
                    DSPRODUTO,
                    NUCODBARRAS,
                    parseInt(QTD),
                    EMPDESTINO,
                    maskValor(parseFloat(VRUNITARIO || 0).toFixed(6), 6),
                    maskValor(parseFloat(VRTOTALPROD || 0).toFixed(6), 6),
                ];
            });

        }

        $('#modalGenerico #resultadoProdParaNFE').html(
            `<table id="dt-lista-produtos-nfe-entrada" class="table table-bordered table-hover table-striped w-100 ">
            <thead class="bg-primary-600">
                <tr >
                    <th style="width: 5px; text-align: center; font-size: 12px;">#</th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>ID Produto<b></th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>Produto<b></th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>Cód.Barras<b></th>
                    <th style="width: 15px; text-align: center; font-size: 12px;"><b>Quantidade<b></th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>Depósito<b></th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>Vr. Unitário<b></th>
                    <th style="width: 10px; text-align: center; font-size: 12px;"><b>Vr.Total<b></th>
                </tr>
            </thead>
            <tbody>
            </tbody>
        </table>`
        );

        $('#modalGenerico #dt-lista-produtos-nfe-entrada').DataTable({
            data: produtosNota,
            autoWidth: false,
            "columnDefs": [
                { "width": "10%", "targets": [3, 5, 6, 7] },
                { "width": "35%", "targets": [2] },
                { "width": "10%", "targets": [1, 4] },
                { "width": "5%", "targets": [0] },
                //{ "className": 'text-right', "targets": [4, 5, 6, 7, 8] },
                { "className": 'text-center', "targets": [0, 1, 2, 3, 4, 5, 6, 7] },
            ],
            "displayLength": 25,
        });
        $('#tituloGenerico').text('Nota Fiscal de Entrada');
        $('#obsNotaEntrada').val(obsNota);
        $('#vrTotalNotaEntrada').val(maskValor(parseFloat(totalNotaEntrada || 0).toFixed(6), 6));
        $('#vrTotalaPagar').val(maskValor(parseFloat(totalNotaEntrada || 0).toFixed(6), 6));
        $('#vrSaldo').val(maskValor(parseFloat(totalNotaEntrada || 0).toFixed(6), 6));




        $('#modalGenerico').modal('show')
        animationLoadingStop()

    } catch (error) {
        animationLoadingStop();
        msgError();
        console.log(error)
        $('#modalGenerico').modal('hide');
    }
}

