function cancelarNFEntradaCadastrada(idResumoEntrada = '') {
    msgQuestion('Deseja realmente cancelar?')
    .then((resp)=>{

        if(resp.value){
            let dadosNFEntrada = [];

            if (idResumoEntrada) {
                animationLoadingStart('Cancelando Nota Fiscal...', false);
                dadosNFEntrada.push({ "IDRESUMOENTRADA": Number(idResumoEntrada) });

                ajaxPut(`api/cadastro/cancelar_nf_entrada.xsjs`, dadosNFEntrada)
                    .then(resp => {
                        animationLoadingStop();

                        if (resp.statusPost == 'Success') {
                            msgSuccess(resp.msg).then(async (resp) => {
                                await pesquisaNfeCadastrada(idResumoEntrada);
                            });
                            
                        } else {
                            msgWarning(resp.msg);
                        }
                    })
                    .catch((error) => {
                        animationLoadingStop();

                        msgError('Erro ao Cancelar a Nota Fiscal, Tente Novemente!');
                        console.log(error);
                    });

            } else {
                msgError('Erro ao Cancelar a Nota Fiscal, Entre em contato com o Suporte Tecnico!');
                console.log('ID da nota inexistente!')
            }

        }
    })

}

function selecionaLinha(id, msg = 'PEDIDO SELECIONADO PARA VINCULAR!') {
    let linhaSelecionada = $(`#${id}`).parent('div').parent('td').parent();
    if (!linhaSelecionada.hasClass('selected')) {
        linhaSelecionada.addClass('selected').css("opacity", 0.8);
        linhaSelecionada.attr('title', `${msg}`);
        $('#footerPedidoVinculadoNFE').removeClass('d-none');

    } else {
        linhaSelecionada.removeClass('selected').removeAttr('style');
        linhaSelecionada.attr('title', 'PEDIDO VINCULADO A ESTA NOTA FISCAL!');
        $('#footerPedidoVinculadoNFE').addClass('d-none');

    }

}

