function criarNFEDevolucao(idNotaFiscal, notaFiscal, fornecedor){
  let startLoading = setTimeout(()=>animacaoCarregamento(), delayMaximo);

  ajaxGet(`api/cadastro/cadastro_produto_nfpedido.xsjs?id=${idNotaFiscal}`)
  .then((resposta)=>{
    retornoProdutosNotaFiscal(resposta, notaFiscal, fornecedor, startLoading);
  })
  .catch((err)=>{
    clearInterval(startLoading)
    Swal.close();
    console.log(err);
    msgError('Erro ao Carregar os Produtos da NFE, Tente novamente!')
  })
}

function retornoProdutosNotaFiscal(dadosDetalheNFE, notaFiscal, fornecedor, startLoading) {
  let dadosDetalhe = dadosDetalheNFE.data.length ? dadosDetalheNFE.data : "";
  let nota = notaFiscal;
  let contadorDet = 0;
  let dadosTable = [];

  $('#tituloGenerico').html(`
    <h3>Produtos para Devolução</h4>
    <h4 class="m-0 text-muted">Nota Fiscal: ${nota}</h4>
    <h4 class="m-0 text-muted"> Fornecedor: ${fornecedor.toUpperCase()}</h4>
  `);

  $('#resultadoModalGenerico').html(`
    <div class="panel-content">
      <table id="DetalheProdutosNFEDev" class="table table-bordered table-hover table-striped table-active w-100 text-center">
        <caption class="fw-700">Fornecedor: ${fornecedor.toUpperCase()}</caption>
        <thead class="bg-primary-600">
          <tr>
            <th><b>Linha<b></th>
            <th><b>Produto<b></th>
            <th><b>Referência<b></th>
            <th><b>NCM<b></th>
            <th><b>Vr Unitario<b></th>
            <th><b>QTD Nota<b></th>
            <th><b>QTD Devolução<b></th>
            <th><b>Vr Total<b></th>
          </tr>
        </thead>
        <tbody></tbody>
        <tfoot></tfoot>
      </table>
    </div>
  `)
  
                

  for (let i = 0; i < dadosDetalhe.length; i++) {
    contadorDet++;
    let dsProduto = dadosDetalhe[i]['XPROD'] ? (dadosDetalhe[i]['XPROD'].toUpperCase()) : "";
    let refProduto = dadosDetalhe[i]['CPROD'] ? dadosDetalhe[i]['CPROD'] : "";
    let ncmProduto = dadosDetalhe[i]['NCM'] ? dadosDetalhe[i]['NCM'] : "";
    let qtdProdutoNFE = dadosDetalhe[i]['QCOM'] ? +dadosDetalhe[i]['QCOM'] : 0;
    let vrUnitario = dadosDetalhe[i]['VUNCOM'] ? maskValor(dadosDetalhe[i]['VUNCOM']) : 'Sem Valor';
    let vrTotal = dadosDetalhe[i]['VPROD'] != 0.00 ? maskValor(dadosDetalhe[i]['VPROD']) : vrUnitario;
    let idProdNFe = dadosDetalhe[i]['IDDETALHEENTRADA'];
    let qtdDevolucao = `
          <div class="input-group d-inline-block">
            <input id="qtdProdConciliar" idprodnfelinha="${idProdNFe}" qtdprodnotalinha="${qtdProdutoNFE}" type="text" style="width: 60px; text-align: center" value="0" onkeyup="mascaraNumero(this, formataNumero)"  onblur="atualizaHistorico(this.value, this)" onclick="historicoDigitado(this.value)">
          </div>
        `;
    
    dadosTable.push([
      contadorDet,
      dsProduto,
      refProduto,
      ncmProduto,
      vrUnitario,
      qtdProdutoNFE,
      qtdDevolucao,
      vrTotal
    ])
  }
  
  $('#DetalheProdutosNFEDev').DataTable({
    data: dadosTable,
    "columnDefs": [
      { "width": "5%", "targets":  [0] },
      { "width": "40%", "targets": [1] },
      { "width": "10%", "targets": [2] },
      { "width": "5%", "targets":  [3] },
      { "width": "10%", "targets": [4] },
      { "width": "10%", "targets": [5] },
      { "width": "10%", "targets": [6] },
      { "width": "10%", "targets": [7] },
      { "className": 'text-left', "targets": [1] },
      { "className": 'text-center', "targets": [0, 2, 3, 4, 5, 6, 7]}

    ],
    "displayLength": 15,
    // "paging":   false,
    // "ordering": false,
    // "info":     false,
    "searching":     true,
    "deferRender":    true
    //scrollY: false,
    // scrollCollapse: false,
    // scroller:       false,
  })

  $('#modalGenerico').modal('show');
  clearInterval(startLoading)
  Swal.close();
}
