            $('#btnConfirmAlteracao').addClass('d-none');

            msg = `O${plural} Campo${plural} de Preço${plural} Novo${plural} Est${plural ? 'ão' : 'á'} Inalterado${plural} ou Zerados, O${plural} Produto${plural} Selecionado${plural} da${plural} Linha${plural}: (${numLinha})`, `Favor Adicionar o Novo Preço ao${plural} Campo${plural}!`;

