function excluirProdAntesDaAlteracao(idProduto){
    arrayProdsParaAlterar = arrayProdsParaAlterar.filter(elemento => elemento.IDPRODUTO !== idProduto);

    msgSuccess(`Produto "${idProduto}" excluído da Alteração!`)
    .then(() => {visualizarProdsAntesDeAlterar(arrayProdsParaAlterar)})
}

async function sobeAlteracaoPrecoProdutos(dadosProdParaAlterar) {
    let dadosProd = [];
    let IDUSER = await getCurrentUser();
    let IDPRODUTO;
    let IDEMPRESA;
    let IDLISTAPRECO;
    let PRECOVENDAANTIGO;
    let PRECOVENDANOVO;
    let DTAGENDAMENTOPERSONALIZADO;
    let STAGENDAMENTOPADRAO;
    let STAGENDAMENTOIMEDIATO;
    let STAGENDAMENTOPERSONALIZADO;

    IDUSER = IDUSER?.user?.id || false;

    if (!IDUSER) {
        animationLoadingStop();
        return msgInfo('Usuário não encontrado, Recarregue a página e tente novamente!');
    }
    
    animationLoadingStart('Verificando e Inserindo Informações...');

  await $.map(dadosProdParaAlterar, async (valor) => {
    if (valor['IDPRODUTO']) {
      IDPRODUTO = valor['IDPRODUTO'];
      IDEMPRESA = valor['IDEMPRESA'];
      IDLISTAPRECO = !IDEMPRESA ? valor['IDLISTAPRECO'] : null;
      PRECOVENDAANTIGO = null;
      PRECOVENDANOVO = Number(valor['PRECO_VENDA']);
      STAGENDAMENTOPADRAO = valor['STAGENDAMENTOPADRAO'];
      STAGENDAMENTOIMEDIATO = valor['STAGENDAMENTOIMEDIATO'];
      STAGENDAMENTOPERSONALIZADO = valor['STAGENDAMENTOPERSONALIZADO'];
      DTAGENDAMENTOPERSONALIZADO = valor['DTAGENDAMENTOPERSONALIZADO']

      dadosProd.push({
        IDPRODUTO,
        IDEMPRESA,
        IDLISTAPRECO,
        PRECOVENDAANTIGO,
        PRECOVENDANOVO,
        IDUSER,
        STAGENDAMENTOPADRAO,
        STAGENDAMENTOIMEDIATO,
        STAGENDAMENTOPERSONALIZADO,
        DTAGENDAMENTOPERSONALIZADO
      });

    } else {
      IDPRODUTO = valor[1];
      IDEMPRESA = valor[8] ? Number(valor[8]) : null;
      IDLISTAPRECO = !IDEMPRESA ? Number(valor[6]) : null;
      PRECOVENDAANTIGO = Number((valor[4]).replace(/\D/g, '').replace(/(\d)(\d{2})$/, '$1.$2'));
      PRECOVENDANOVO = Number((valor[5]).replace(/\D/g, '').replace(/(\d)(\d{2})$/, '$1.$2'));
      STAGENDAMENTOPADRAO = valor[9];
      STAGENDAMENTOIMEDIATO = valor[10];
      STAGENDAMENTOPERSONALIZADO = valor[11];
      DTAGENDAMENTOPERSONALIZADO = valor[12]

      dadosProd.push({
        IDPRODUTO,
        IDEMPRESA,
        IDLISTAPRECO,
        PRECOVENDAANTIGO,
        PRECOVENDANOVO,
        IDUSER,
        STAGENDAMENTOPADRAO,
        STAGENDAMENTOIMEDIATO,
        STAGENDAMENTOPERSONALIZADO,
        DTAGENDAMENTOPERSONALIZADO
      });

    }

  });
    
    $('#modalGenerico').modal('hide');
    
    ajaxPost(`api/produtos/alteracao-preco-produto.xsjs`, dadosProd)
        .then((resp) => {
            animationLoadingStop()

            if (resp?.type == 'success') {
                let IDRESUMOALTERACAOPRECO = resp.IDRESUMOALTERACAOPRECO;

              $('#modalGenerico').modal('hide');

                Swal.fire({
                    type: 'success',
                    title: 'Alteração Realizada Com Sucesso!',
                    showConfirmButton: true,
                    allowOutsideClick: false,
                    allowEscapeKey: false
                }).then(async (resp) => {
                    await TelaAlteracoesPreco();

                    animationLoadingStart('Carregando Alteração...');

                    let respPesq = await ajaxGetAllData(`api/produtos/alteracoes-de-precos-resumo.xsjs?id=${IDRESUMOALTERACAOPRECO}`, false);

                    retornoPesquisaAlteracoesPreco(respPesq);
                    animationLoadingStop();
                });

                verificaModoAcumulacao = '';
                acumuladorProdsAlteracao;
                indexPreviousFocus = '';
                arrayProdsParaAlterar = '';
            } else {
                let numLinha = '';
                let plural = '';
                let idsProds = '';

                if (resp?.idsprodutos) {
                    let idsProdutos = resp.idsprodutos;

                    idsProdutos.map((valor, indice) => {
                        numLinha.length >= 1 ? (plural = 's', idsProds += ', ') : plural = '';
                        numLinha += indice
                        idsProds += valor;
                    })

                    Swal.fire({
                        type: 'warning',
                        html: `
                            <div>
                                <p class="font-weight-bold text-dark">O${plural} Produto${plural} com o${plural} ID${plural}:</p>
                                <p class="text-dark">${idsProds}</p>
                                <p class="font-weight-bold text-dark"> Não Fo${plural ? 'ram' : 'i'} Encontrado${plural} no Cadastro de Produtos!</p>
                                
                                <p class="font-weight-bold text-dark mt-3 mb-0">Lista de Produtos não Encontrados:</p>
                                <textArea id="List_Prods_Not_Found" value="${idsProds}" style="width: 100%; height: 25%" rows="30" readonly>${idsProds}</textArea>
                            </div>
                        `,
                        text: `Favor Verificar o${plural} ID${plural} inserido${plural} no Arquivo Importado!`,
                        showConfirmButton: true,
                        allowOutsideClick: false,
                        allowEscapeKey: false,
                        onOpen: () => {
                            const textarea = document.getElementById('List_Prods_Not_Found');
                            textarea.focus();
                            textarea.select();
                        }
                    }).then(()=>{
                        $('#modalGenerico').modal('show');
                    })
                    

                } else {
                    msgWarning(resp?.msg)//.then(resp => AlteracaoDePrecoProd());

                    console.log(resp)
                }
            }
        })
        .catch((error) => {
            console.log(error)
            animationLoadingStop();
            
            $('#modalGenerico').modal('hide');
            
            msgError('Erro ao Editar os Preços, Tente Novamente')
            console.log(error);
        });

}

