async function telaCreateEditListaPrecos() {
    animationLoadingStart();
    
    try{
        await $.get("action_ListasPreco.html", function (resp) {
            $('#js-page-content').html(resp);
            
            $('#dataInicio, #dataFim').val(dataAtualCampo);
            
            $('#selectLojasLista').select2();
            
            $('#dataInicio, #dataFim, #idLista, #nomeLista').on('keypress', (e) => { if (e.keyCode == 13) pesquisaListasPreco() });
        }).fail((error) => { throw error});
        
       let respEmpresas = await ajaxGetAllData(`api/empresa.xsjs?`, false);
        retornoSelectListadePrecosLojas(respEmpresas);
        
        let respListas = await ajaxGetAllData(`api/listas-de-precos.xsjs`, false);
        retornoPesquisaListasPreco(respListas);
        
        animationLoadingStop()
        
    } catch (error) {
        animationLoadingStop()
        console.log(error)
        msgError(error);
    }


}

function retornoSelectListadePrecosLojas(respostaListadePreços) {
    let listaPreco = respostaListadePreços.data.length ? respostaListadePreços.data : '';

    if (listaPreco) {
        $('#selectLojasLista').html('');
        
        $('#selectLojasLista').append(`<option value="">Selecione...</option>`);
        
        for (let lista of listaPreco) {
            $('#selectLojasLista').append(`
              <option title="LOJA" value="${lista['IDEMPRESA']}">${lista['NOFANTASIA']}</option>
            `);
        }
    }

}

async function pesquisaListasPreco(idListaRetorno = '') {
    animationLoadingStart();
    
    try{
        let idLoja = !idListaRetorno ? $('#selectLojasLista').val().trim() : '';
        let idLista = !idListaRetorno ? $('#idLista').val().trim() : idListaRetorno;
        let nomeLista = !idListaRetorno ? $('#nomeLista').val().trim() : '';
        let dtInicio = '';
        let dtFim = '';
        
        if (!idLoja && !idLista && !nomeLista && !idListaRetorno) {
            dtInicio = $('#dataInicio').val();
            dtFim = $('#dataFim').val();
        }
        
        let respDados = await ajaxGetAllData(`api/listas-de-precos.xsjs?dtInicio=${dtInicio}&dtFim=${dtFim}&idLoja=${idLoja}&idLista=${idLista}&nomeLista=${nomeLista}`, false);
        retornoPesquisaListasPreco(respDados);
        
        animationLoadingStop();
        
    } catch (error) {
        
        animationLoadingStop();    
        msgError();
        console.log(error)
    }
    
}

function retornoPesquisaListasPreco(respostaPesquisaListasPrecos) {
    // $('#idProdAlteracao').val('');
    // $('#selectLojasLista').val('').trigger('change');
    // $('#idLista').val('')
    // $('#nomeLista').val('');

    let dadosListasPreco = respostaPesquisaListasPrecos.data || '';
    let dadosTable = [];

    if (dadosListasPreco.length) {
        let contador = 0;

        for (let i = 0; i < dadosListasPreco.length; i++) {
            let lista = dadosListasPreco[i]['listaPreco'];
            let qtdLojasLista = dadosListasPreco[i]['detalheLista'];
            let idLista = lista.IDRESUMOLISTAPRECO;
            let nomeLista = lista.NOMELISTA;
            let dtCriacao = lista.DATACRIACAO || '';
            let dtAlteracao = lista.DATAALTERACAO || '';
            let statusLista = lista.STATIVO == 'True' ? `<label class="font-weight-bold text-info">ATIVA</label>` : `<label class="font-weight-bold text-danger">INATIVA</label>`;

            let opcoes = `
            <div class="btn-group btn-group-xs pt-0 pb-0">
                <button id="btnDetalheLista" type="button" class="btn btn-success btn-xs pt-1 pb-1" title="Visualizar Lojas da Lista" value="${idLista}"><span class="fal fa-list p-1"></span></button>

                <button id="btnEditLista" type="button" class="btn btn-warning btn-xs pt-1 pb-1" title="Editar Lista de Preço" value="${idLista}" onclick="editarListaPreco(this.value)"><span class="fal fa-pen p-1 text-white"></span></button>
            </div>
          `;

            contador++;
            qtdLojasLista = qtdLojasLista.length;

            dadosTable.push([
                contador,
                idLista,
                nomeLista,
                qtdLojasLista,
                dtCriacao,
                dtAlteracao,
                statusLista,
                opcoes
            ]);
        
        }
        
    }

    $('#resultadoListasPreco').html(`
        <div class="col-sm-12 col-xl-12">
          <table id="dt-basic-lista-preco" class="table table-bordered table-hover table-striped w-100">
            <thead class="bg-primary-600">
                <tr>
                  <th>#</th>
                  <th>Número Lista</th>
                  <th>Nome</th>
                  <th>Qtd. Lojas</th>
                  <th>Data Criação</th>
                  <th>Data Alteração</th>
                  <th>Status</th>
                  <th>Opções</th>
                </tr>
            </thead>
            <tbody>
            </tbody>
            <tfoot>
            </tfoot>
          </table>
        </div>
      `);

    let alturaTela = $(window).height();
    alturaTela = alturaTela * 0.7;

    let tableListaPreco = $('#dt-basic-lista-preco').DataTable({
        data: dadosTable,
        defaultContent: '',
        paging: true,
        pageLength: 50,
        searching: true,
        info: false,
        deferRender: true,
        // responsive: true,
        scrollY: alturaTela,
        scrollX: true,
        columnDefs: [
            {
                targets: [0, 1, 3, 4, 5, 6, 7],
                className: 'tdCenter'
            }
        ],
        language: {
            "emptyTable": "Dados não encontrados!"
        }
    });

    $('#dt-basic-lista-preco tbody').on('click', 'button#btnDetalheLista', async function () {
        try{
            var tr = $(this).closest('tr');
            var row = tableListaPreco.row(tr);
            var numListaLinha;
    
            if (tr.hasClass('child')) {
                tr = $($(`#${$(this).attr('value')}`).closest('tr'))
    
                row = tableListaPreco.row(tr);
                numListaLinha = $(this).attr('value');
    
                row.child.hide();
                tr.removeClass('shown');
    
            } else {
                row = tableListaPreco.row(tr);
                numListaLinha = $(this).attr('value')
            }
    
    
            if (row.child.isShown()) {
                // This row is already open - close it
                row.child.hide();
                tr.removeClass('shown');
    
            } else {
                animationLoadingStart('Carregando Detalhes da Lista');
    
                ajaxGet(`api/listas-de-precos.xsjs?idLista=${numListaLinha}`)
                    .then(async (resp) => {
                        
                        row.child(insereCabecalhoAccordionListaPreco(resp, numListaLinha)).show();
                        
                        transformaAccordionDataTable(resp, numListaLinha)
                        
                        animationLoadingStop();
                    })
                    .catch((error) => {
                        throw error;
                    })
                // row.child(formatDataTableVenda(numListaLinha)).show();
                tr.addClass('shown');
            }
        } catch(error){
            animationLoadingStop()
            
            console.log(error)
            msgError('Erro ao carregar os detalhes da lista de preço, tente novamente!');
        }

    });


}

function insereCabecalhoAccordionListaPreco(detalhesLista, idLista) {
    let detalheLista = detalhesLista.data[0];

    htmlTableAccordion = `
        <div class="row">
            <div class="col-xl-12 col-sm-12">
                <div id="panel-1" class="panel">
                <div class="panel-hdr flex-column align-items-start pl-4 h6">
                    <p class="pl-0 mt-3 mb-0">Número da Lista: <b>${detalheLista['listaPreco']['IDRESUMOLISTAPRECO']}</b></p>
                    <p class="mt-1 mb-0">Nome da Lista: <b>${detalheLista['listaPreco']['NOMELISTA']}</b></p>
                    <p class="mt-1 mb-0">Quantidade de Lojas na Lista: <b>${detalheLista['detalheLista'].length} Lojas</b></p>
                    <p class="mt-1 mb-2">Lojas da Lista de Preço:</p>
                </div>
                <div class="panel-container show">
                    <div class="panel-content">
                        <table id="tbLojaLista_${idLista}" class="table table-bordered table-hover table-striped w-100 text-center">
                        <thead class="bg-primary-400" style="pointer-events: none;">
                                <tr>
                                <th><b>#<b></th>
                                <th><b>Id Loja<b></th>
                                <th class="text-center"><b>Nome Loja<b></th>
                                <th><b>Status<b></th>
                                </tr>
                            </thead>
                        </table>
                    </div>
                    </div>
                </div>
                </div>
            </div>
        </div>`;

    return htmlTableAccordion;
}

function transformaAccordionDataTable(detalhesLista, idLista) {
    let detalheLista = detalhesLista.data[0]['detalheLista'];
    let dadosTable = [];
    for (let i = 0; i < detalheLista.length; i++) {
        let idEmpresa = detalheLista[i]['loja']['IDEMPRESA'];
        let nomeLoja = detalheLista[i]['loja']['NOFANTASIA'];
        let stativo = detalheLista[i]['loja']['STATIVO'] == 'True' ? `<label class="font-weight-bold text-info">ATIVA</label>` : `<label class="font-weight-bold text-danger">INATIVA</label>`

        dadosTable.push([
            i + 1,
            idEmpresa,
            nomeLoja,
            stativo
        ])
        /*html += `        <tbody>
                          <tr>
                            <td>${i+1}</td>
                            <td>${detalheLista[i]['loja']['IDEMPRESA']}</td>
                            <td class="text-left">${detalheLista[i]['loja']['NOFANTASIA']}</td>
                            <td>${stativo}</td>
                          </tr>
                      </tbody>`;*/
    }


    $(`#tbLojaLista_${idLista}`).DataTable({
        data: dadosTable,
        defaultContent: '',
        paging: true,
        pageLength: 50,
        searching: true,
        info: false,
        deferRender: true,
        scrollY: '400px',
        responsive: true,
        language: {
            "emptyTable": "Dados não há lojas nesta lista!"
        },
        columnDefs: [
            {
                targets: [2],
                className: 'text-left'
            }
        ],
    })

}

async function criarListaPreco() {
    animationLoadingStart();

    try {
        await CarregarActionCreateEditListaPrecoModal('create').catch((error) => { throw error} );
        await abrirModalCreateEditListaPreco().catch((error) => { throw error} );
        await CarregarCreateEditDetalhesListaPrecoModal('create').catch((error) => { throw error} );
        
        animationLoadingStop();
        
    } catch (error) {
       animationLoadingStop();
        
        msgError('Erro ao carregar os detalhes da lista de preço, tente novamente!');
        console.log(error)
    }
}

async function editarListaPreco(idLista) {
    animationLoadingStart();
    
    try{
        let respLista = await ajaxGetAllData(`api/listas-de-precos.xsjs?idLista=${idLista}`, false).catch((error) => { throw error })
        retornoEditarListaPreco(respLista);
        
    } catch(error){
        animationLoadingStop();
        msgError();
        console.log(error)
    }
}

async function retornoEditarListaPreco(dadosListaPreco) {
    try {
        await CarregarActionCreateEditListaPrecoModal('edit').catch((error) => { throw error });
        await CarregarEditCabecalhoListaModal(dadosListaPreco).catch((error) => { throw error });
        await abrirModalCreateEditListaPreco().catch((error) => { throw error } );
        await CarregarCreateEditDetalhesListaPrecoModal('edit', dadosListaPreco).catch((error) => { throw error });
        
        animationLoadingStop();
    } catch (error) {
        animationLoadingStop();
        msgError('Erro ao carregar os detalhes da lista de preço, tente novamente!');
        console.log(error)
    }
}

async function abrirModalCreateEditListaPreco() {
   return new Promise(async (resolve, reject) => {
        $('#modalGenerico .modal-dialog').removeClass('modal-xl').addClass('modal-lg');

        $('#modalGenerico').modal({
            backdrop: 'static',
            keyboard: false
        });

        $('#modalGenerico').modal('show');

        setTimeout(() => resolve(), 200);
    })
}

async function CarregarActionCreateEditListaPrecoModal(modo = 'edit') {
    try{
        await $.get("action_EditListasPreco.html", function (resp) {
            $('#resultadoModalGenerico').html(resp);
            
            if (modo == 'create') {
                $('#statusListaPreco').attr('disabled', true);
                $('#dtCreateListaPreco').val(dataAtualCampo);
                $('#dtAlterListaPreco').val(dataAtualCampo);
            }
            
            $('#statusListaPreco').select2();
            $('#modalGenerico .select2-selection__rendered').addClass('font-weight-bold');
            $('#modalGenerico .select2-results').addClass('font-weight-bold');
            
            if ($('#statusListaPreco').val() == 'True') {
                $('#modalGenerico .select2-selection__rendered').removeClass('text-danger').addClass('text-info');
            } else {
                $('#modalGenerico .select2-selection__rendered').removeClass('text-info').addClass('text-danger');
            }
            
            $('#statusListaPreco').on('select2:open', () => {
                $('.select2-results').addClass('font-weight-bold');
                
                setTimeout(() => {
                    $('.select2-results__option').each(function () {
                        if ($(this).text().trim() == 'INATIVA') {
                            $(this).addClass('text-danger');
                        } else {
                            $(this).addClass('text-info');
                        }
                    });
                    
                }, 10);
            });
            
            $('#statusListaPreco').on('select2:closing', () => {
                if ($('#statusListaPreco').val() == 'True') {
                    $('#modalGenerico .select2-selection__rendered').removeClass('text-danger').addClass('text-info');
                } else {
                    $('#modalGenerico .select2-selection__rendered').removeClass('text-info').addClass('text-danger');
                }
            });
            
        }).catch((error) => { throw error} );
        
    } catch(erro){
        msgError();
        console.log(error)
    }
}

async function CarregarEditCabecalhoListaModal(dadosListaPreco) {
    let dados = dadosListaPreco.data[0];
    let nomeLista = dados['listaPreco']['NOMELISTA'] || '';
    let dtCreate = dados['listaPreco']['DTCREATE'] || '';
    let dtAlter = dados['listaPreco']['DTALTER'] || '';

    dtCreate = dtCreate ? dtCreate.split('T').shift() : dtCreate;
    dtAlter = dtAlter ? dtAlter.split('T').shift() : dtCreate;

    $('#dtCreateListaPreco').val(dtCreate);
    $('#dtAlterListaPreco').val(dtAlter);
    $('#idListaPreco').val(dados['listaPreco']['IDRESUMOLISTAPRECO']);
    $('#nomeListaPreco').val(dados['listaPreco']['NOMELISTA']);
    $('#statusListaPreco').val(dados['listaPreco']['STATIVO']).trigger('change');

    $('#tituloGenerico').text('Edição de Lista de Preços');
    $('#tituloGenerico').append(`
          <small class="m-0 text-muted">
              Lista de Preço: ${nomeLista} 
          </small>
    `);
}

async function CarregarCreateEditDetalhesListaPrecoModal(modo = 'edit', dadosListaPreco = '') {
    let detalhes = dadosListaPreco ? dadosListaPreco.data[0]['detalheLista'] : '';
    let idLista = dadosListaPreco ? dadosListaPreco.data[0]['listaPreco'].IDRESUMOLISTAPRECO : '';
    let dadosTable = [];
    let lojas = await ajaxGet('api/empresa.xsjs?');
    let contador = 0;

    lojas = lojas.data;

    if (modo == 'edit') {
        detalhes.map(dados => {
            let detalhe = dados['loja'];
            let idDetalheLista = detalhe.IDDETALHELISTAPRECO
            let idGrupoEmpresarial = detalhe.IDGRUPOEMPRESARIAL
            let idEmpresa = detalhe.IDEMPRESA;
            let nomeEmpresa = detalhe.NOFANTASIA;
            let stAtivo = detalhe.STATIVO;
            let opcao = `
                <div class="custom-control custom-checkbox"> 
                    <input type="checkbox" class="custom-control-input" name="selecaoLojaParaLista" id="${idEmpresa}" idGrupoEmpresarial=${idGrupoEmpresarial} idLista=${idLista} idDetalheLista="${idDetalheLista}" stAtivoLojaLista="${stAtivo}" onchange="selecionaLinhaLojaListaPreco(this.id)" disabled><label class="custom-control-label" for="${idEmpresa}"></label>
                </div>
            `;

            stAtivo = `<label idEmpresa=${idEmpresa} idLista=${idLista} onclick="changeStatusLojaLista(this)" class="font-weight-bold text-${stAtivo == 'True' ? 'info " stLojaLista="True">ATIVA' : 'danger " stLojaLista="False">INATIVA'}</label>`;

            contador++;

            dadosTable.push([
                contador,
                opcao,
                idEmpresa,
                nomeEmpresa,
                stAtivo
            ])
        })
    }

    lojas.map(dados => {
        let detalhes = dados;
        let idGrupoEmpresarial = detalhes.IDGRUPOEMPRESARIAL;
        let idEmpresa = detalhes.IDEMPRESA;
        let nomeEmpresa = detalhes.NOFANTASIA;
        let stAtivo = detalhes.STATIVO;
        let validaInclusao = false;

        let opcao = `
            <div class="custom-control custom-checkbox"> 
                <input type="checkbox" class="custom-control-input" name="selecaoLojaParaLista" id="${idEmpresa}" idGrupoEmpresarial=${idGrupoEmpresarial} idLista=${idLista} idDetalheLista="" stAtivoLojaLista="False" onchange="selecionaLinhaLojaListaPreco(this.id)"><label class="custom-control-label" for="${idEmpresa}"></label>
            </div>
        `;

        stAtivo = `<label class="font-weight-bold text-danger" idEmpresa=${idEmpresa} idLista=${idLista} onclick="changeStatusLojaLista(this)">INATIVA</label>`;
        dadosTable.map(arrayInterno => arrayInterno[2] == idEmpresa && !validaInclusao ? validaInclusao = true : null);

        if (!validaInclusao || modo == 'create') {
            contador++

            dadosTable.push([
                contador,
                opcao,
                idEmpresa,
                nomeEmpresa,
                stAtivo
            ])
        }
    })

    let tabelaLojas = `  
        <div class="row mt-3">
            <div class="col-xl-12 col-sm-12">
                <div id="panel-1" class="panel">
                    <div class="panel-hdr pl-3">
                        <h6>Lista de Lojas </h6>
                    </div>
                    <div class="panel-container show">
                        <div class="panel-content">
                            <table id="tbLojaListaModal" class="table table-bordered table-hover table-striped w-100 text-center">
                                <thead class="bg-primary-600">
                                    <tr>
                                    <th><b>#<b></th>
                                    <th><b>Selecione<b></th>
                                    <th><b>Id Loja<b></th>
                                    <th class="text-center"><b>Nome Loja<b></th>
                                    <th><b>Status na lista<b></th>
                                    </tr>
                                </thead>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    `;

    $('#resultadoLojasListaPrecoModal').html(tabelaLojas);

    $('#tbLojaListaModal').DataTable({
        data: dadosTable,
        defaultContent: '',
        paging: true,
        pageLength: -1,
        searching: true,
        info: true,
        deferRender: true,
        responsive: true,
        scrollY: '500px',
        language: {
            "emptyTable": "Dados não encontrados, tente novamente!"
        },
        columnDefs: [
            {
                targets: [3],
                className: 'text-left'
            }
        ],
    });


    modo == 'edit' && detalhes.map(arrayInterno => {
        selecionaLinhaLojaListaPreco(arrayInterno['loja'].IDEMPRESA, 'EMPRESA PERTENCENTE A LISTA DE PREÇO', '', arrayInterno['loja'].STATIVO)
    });

    let buttonCreateEdit =`
        <button  class="btn btn-success" type="button" ${modo == 'create' ? `title="Criar Lista de Preco" onclick="createUpdateListaPreco('create')">
            <span class="fal fa-plus mr-1"></span>Criar Lista` : `title="Atualizar Lista de Preco" onclick="createUpdateListaPreco('edit')">
            <span class="fal fa-pen mr-1"></span>Atualizar Lista`}
        </button>
    `;

    $('#footerModalGenerico').html(`
        <button id="btnCloseEditListaPreco" class="btn btn-danger" type="button" title="Cancelar e Fechar">
        <span class="fal fa-times mr-1"></span>Cancelar e Fechar
        </button>
        ${buttonCreateEdit}
    `);

    $('#btnCloseEditListaPreco').on('click', () => $('#modalGenerico').modal('hide'));
}

function changeStatusLojaLista(element, status = undefined) {
    let idInputLinha = $(element).attr('idempresa');

    if (!$(`#${idInputLinha}`).prop('checked') && status == undefined) {
        return msgWarning('Empresa não selecionada para a lista, selecione primeiro a loja e tente novamente!');
    }

    if ($(element).hasClass('text-info') && !status || status == 'False') {
        $(element).removeClass('text-info').addClass('text-danger').text('INATIVA');

        $(`#${idInputLinha}`).attr('stAtivoLojaLista', 'False');
    } else {
        $(element).removeClass('text-danger').addClass('text-info').text('ATIVA');

        $(`#${idInputLinha}`).attr('stAtivoLojaLista', 'True')
    }
}

function selecionaLinhaLojaListaPreco(id, msgSelected = 'EMPRESA SELECIONADA PARA A LISTA DE PREÇO!', msgNotSelected = 'EMPRESA NÃO SELECIONADA PARA A LISTA DE PREÇO!', status = '') {
    let linhaSelecionada = $('#' + id).closest('tr');
    let inputStAtivo = linhaSelecionada.find('label:last');

    linhaSelecionada.toggleClass('selected').css("opacity", linhaSelecionada.hasClass('selected') ? (0.8, $('#' + id).attr('checked', true), changeStatusLojaLista(inputStAtivo, status || true)) : (1, $('#' + id).attr('checked', false), changeStatusLojaLista(inputStAtivo, false)));
    linhaSelecionada.attr('title', linhaSelecionada.hasClass('selected') ? msgSelected : msgNotSelected);
}

async function createUpdateListaPreco(modo = 'create') {
    try{
        let idUserSessao = await getCurrentUser()?.user?.id;
        let lojasSelecionadas = $('[name="selecaoLojaParaLista"]:checked');
        let dadosLista = [];
        let dadosDetalheLista = [];
        let IDRESUMOLISTAPRECO = Number($('#idListaPreco').val());
        let NOMELISTA = $('#nomeListaPreco').val()
        let IDUSERCRIACAO = modo == 'create' ? idUserSessao : '';
        let IDUSERALTERACAO = modo == 'edit' ? idUserSessao : '';
        let STATIVO = $('#statusListaPreco').val();
        
        if(!idUserSessao){
            return msgError('Não foi possivel localizar os dados do usuário, faça o logoff e entre novamente no sistema');
        }
        
        await lojasSelecionadas.map(async (i, dados) => {
            let loja = $(dados);
            let IDDETALHELISTAPRECO = loja.attr('idDetalheLista') ? Number(loja.attr('idDetalheLista')) : '';
            let IDGRUPOEMPRESARIAL = loja.attr('idGrupoEmpresarial') ? Number(loja.attr('idGrupoEmpresarial')) : '';
            let IDEMPRESA = loja.attr('id') ? Number(loja.attr('id')) : '';
            let STATIVO = loja.attr('stativolojalista');
    
            dadosDetalheLista.push({
                IDDETALHELISTAPRECO,
                IDRESUMOLISTAPRECO,
                IDGRUPOEMPRESARIAL,
                IDEMPRESA,
                STATIVO
            })
        }),
    
            dadosLista.push({
                IDRESUMOLISTAPRECO,
                NOMELISTA,
                IDUSERCRIACAO,
                IDUSERALTERACAO,
                STATIVO,
                lojas: dadosDetalheLista
            });
    
    
        if (!dadosLista[0]?.NOMELISTA.length || dadosLista[0]?.NOMELISTA.length < 10) {
            return msgWarning('Lista Sem Nome ou Nome Muito Curto, favor adicionar o nome da lista e tentar novamente!');
    
        } else if (!dadosDetalheLista.length) {
            return msgWarning('Lista Sem Lojas Selecionadas, favor selecionar as lojas e tentar novamente!');
    
        } else {
            if (modo == 'create') {
                animationLoadingStart('Criando Lista de Preços...');
                
                await ajaxPost('api/listas-de-precos.xsjs', dadosLista)
                    .then(resp => {
                       animationLoadingStop();
                        
                        if (resp.typeMsg == "success") {
                            msgSuccess(resp.msg).then(() => {
                                $('#modalGenerico').modal('hide');
                                
                                pesquisaListasPreco(resp.IDRESUMOLISTAPRECO);
                            });
                        } else {
                            msgWarning(resp.msg);
                        }
                    })
                    .catch((error) => { throw error });
            } else {
                animationLoadingStart('Atualizando a Lista de Preços...');
                
                await ajaxPut('api/listas-de-precos.xsjs', dadosLista)
                    .then(resp => {
                        animationLoadingStop();
                        
                        if (resp.typeMsg == "success") {
                            msgSuccess(resp.msg).then(() => {
                                $('#modalGenerico').modal('hide');
                                
                                pesquisaListasPreco(resp.IDRESUMOLISTAPRECO);
                            });
                            
                        } else {
                            msgWarning(resp.msg);
                        }
                    })
                    .catch((error) => { throw error });
            }
        }
        
    } catch(error){
        animationLoadingStop();
        msgError();
        console.log(error);
    }
}

// === FIM ROTINA LISTAS DE PRECOS - CRIACAO E EDICAO DE LISTA DE PRECO === //